import (
	"github.com/openmeterio/openmeter/openmeter/event/metadata"
	"github.com/openmeterio/openmeter/openmeter/event/models"
	"github.com/openmeterio/openmeter/openmeter/watermill/marshaler"
)

var (
	_ marshaler.Event = EventNewIngest{}
	newIngestEventType = metadata.EventType{
		Subsystem: EventSubsystem,
		Name:      "events.new",
		Version:   "v1",
	}
	newIngestEventName       = metadata.GetEventName(newIngestEventType)
	NewIngestVersionSubsystem = newIngestEventType.VersionSubsystem()
)

type EventNewIngest struct {
	Namespace  models.NamespaceID `json:"namespace"`
	MeterSlugs []string           `json:"meterSlugs"`
}

func (e EventNewIngest) EventName() string { return newIngestEventName }

func (e EventNewIngest) Validate() error {
	if err := e.Namespace.Validate(); err != nil {
		return err
	}
	return nil
}

func (e EventNewIngest) EventMetadata() metadata.EventMetadata {
	return metadata.EventMetadata{
		Source: metadata.ComposeResourcePathRaw(string(EventSubsystem)),
	}
}
